const output = $input.first().json.output || '';
const message = output.toLowerCase();

// Check if bot is asking a confirmation question
const isBookingConfirmation = 
  message.includes('أأكد') ||
  message.includes('أكد لي') ||
  message.includes('تأكيد الحجز') ||
  message.includes('أحجز لك') ||
  message.includes('نحجز') ||
  message.includes('confirm');

const isTimeSelection = 
  message.includes('أي وقت') ||
  message.includes('يناسبك') ||
  message.includes('متى تبين') ||
  message.includes('أي يوم');

const isServiceSelection =
  message.includes('أي خدمة') ||
  message.includes('إيش تبين') ||
  message.includes('شو تحبين');

const isQuestion = message.includes('؟') || message.includes('?');

let questionType = null;
if (isBookingConfirmation) questionType = 'booking_confirm';
else if (isTimeSelection) questionType = 'time_select';
else if (isServiceSelection) questionType = 'service_select';
else if (isQuestion) questionType = 'general';

return {
  json: {
    ...$input.first().json,
    is_bot_question: questionType !== null,
    question_type: questionType
  }
};
